<template><el-card><template #header>原始文件管理</template><PageToolbar><el-input v-model="q" placeholder="搜索文件" clearable/><template #actions><el-upload :show-file-list="false" :before-upload="upload"><el-button type="primary">上传文件</el-button></el-upload></template></PageToolbar><DataTable :data="filtered"><el-table-column prop="name" label="文件名" min-width="220"/><el-table-column prop="type" label="类型"/><el-table-column prop="parseStatus" label="解析状态"/><el-table-column prop="compileStatus" label="编译状态"/><el-table-column prop="duplicateStatus" label="重复检测"/><el-table-column prop="source" label="来源"/><el-table-column prop="uploader" label="上传人"/><el-table-column prop="uploadedAt" label="上传时间"/><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="preview=s.row">预览</el-button><el-button link @click="s.row.compileStatus='已编译'">重新编译</el-button></template></el-table-column></DataTable><el-dialog v-model="open" :title="preview?.name" width="720"><pre>{{preview?.content}}</pre></el-dialog></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { files } from '@/mock/data'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(files))); const q=ref(''); const filtered=computed(()=>rows.value.filter(i=>!q.value||i.name.includes(q.value))); const preview=ref<any>(); const open=computed({get:()=>!!preview.value,set:v=>{if(!v)preview.value=null}}); function upload(file:File){rows.value.unshift({id:Date.now(),name:file.name,type:file.name.split('.').pop()?.toUpperCase(),parseStatus:'待解析',compileStatus:'待编译',duplicateStatus:'检测中',source:'本地上传',uploader:'当前用户',uploadedAt:'刚刚',content:'新上传文件预览占位'}); return false}</script>
